jira.description:
# Установи Node.js (если ещё не установлен). Перейди на [https://nodejs.org|https://nodejs.org|smart-link]  и установи LTS-версию. Проверь установку в терминале:

{noformat}node -v{noformat}

{noformat}npm -v{noformat}

# Установи Playwright
{noformat}npm install -D @playwright/test{noformat}
{noformat}npx playwright install{noformat}

# Разархивировать архив в какой-то удобной для тебя папке.
#  Открыть терминал в этой папке
# Выполнить там команду
{noformat}npx playwright test --project="Mobile Safari" --ui{noformat}

# он откроет тебе веб интерфейс PlayWright, и там попробовать запустить тест кнопкой Play
например: men_dev_bye_with_pdf.spec.ts
